const event = $json.body || $json;
const validTypes = [
  'daily_log.created','daily_log.updated',
  'breakdown.created','breakdown.updated','breakdown.completed',
  'safety_incident.created','safety_incident.updated','safety_incident.resolved',
  'production_log.created','production_log.updated',
  'operational_delay.created','operational_delay.updated'
];
if (!validTypes.includes(event.type)) {
  return { error: 'Invalid event type', received: event.type };
}
return { event, routedAt: new Date().toISOString() };

const { event } = $json;
const actions = [];
if (event.type.startsWith('breakdown.')) {
  actions.push('notify_engineering', 'update_machine_status');
}
if (event.type.startsWith('safety_incident.')) {
  actions.push('notify_safety', 'update_compliance_log');
}
if (event.type.startsWith('production_log.')) {
  actions.push('update_dashboard', 'sync_to_erp');
}
if (event.type.startsWith('operational_delay.')) {
  actions.push('notify_control_room', 'update_shift_report');
}
return { ...$json, actions, dispatched: actions.length };

const { event, actions, routedAt } = $json;
return {
  status: 'routed',
  eventType: event.type,
  department: event.department || 'unknown',
  actions,
  routedAt,
  processedAt: new Date().toISOString()
};
